import test from 'node:test';
import assert from 'node:assert/strict';
import { validateTlsConfig } from '../src/tls-config.mjs';
import { buildTlsOptions } from '../src/tls-options.mjs';

test('required client authentication needs explicit trust material', () => {
  assert.throws(
    () => validateTlsConfig({
      cert: 'server-cert',
      key: 'server-key',
      clientAuth: 'required',
    }),
    /ca|trust/i,
  );
});

test('required mode requests a certificate and rejects untrusted peers', () => {
  assert.deepEqual(buildTlsOptions({
    cert: 'server-cert',
    key: 'server-key',
    ca: 'client-ca',
    clientAuth: 'required',
  }), {
    cert: 'server-cert',
    key: 'server-key',
    ca: 'client-ca',
    requestCert: true,
    rejectUnauthorized: true,
  });
});
